mapper.update:
UPDATE guide_search
SET embedding = #{embeddingStr}::vector
WHERE guide_id = #{guideId}

mapper.select:
SELECT gs.guide_id AS guideId, gs.title, LEFT(gs.content, 300) AS headline, gs.game_id AS gameId, gs.game_name AS gameName, gs.updated_at AS updatedAt FROM guide_search gs WHERE gs.embedding IS NOT NULL
AND gs.game_id = #{gameId}
ORDER BY gs.embedding <=> #{embeddingStr}::vector LIMIT #{topK}
